import { existsSync, statSync, readdirSync, mkdirSync, copyFileSync, readFileSync, writeFileSync } from 'node:fs';
import { join, dirname, relative } from 'node:path';
import chalk from 'chalk';
import ora from 'ora';
import { getCoreDir, getProjectRoot } from '../utils/paths.js';

interface SyncAppOptions {
  dryRun?: boolean;
  force?: boolean;
  backup?: boolean;
  verbose?: boolean;
}

// Patterns to exclude from template sync
// (templates) = Next.js route groups auto-generated by theme system
const EXCLUDED_TEMPLATE_PATTERNS = ['(templates)'];

// Root template files that should be synced to project root (not /app)
// These are critical files that must stay in sync with core
const ROOT_TEMPLATE_FILES = [
  'proxy.ts',           // Next.js 16+ proxy (formerly middleware.ts) - required for auth/permission validation
  'next.config.mjs',    // Required for webpack aliases, transpilePackages, security headers
  'tsconfig.json',      // Required for proper path aliases and test file exclusions
  'i18n.ts',            // Required for next-intl configuration
];

// Root files that contain project-specific customizations and should
// only be created on first sync, never overwritten after that.
// These are treated like custom template files in contents/themes/*/templates/.
const PROTECTED_ROOT_FILES = [
  'tsconfig.json',      // Projects add custom path aliases (e.g. @shared/*)
  'next.config.mjs',    // Projects add custom webpack aliases, plugins, etc.
];

/**
 * Detect if a project has PPR enabled (cacheComponents: true in next.config).
 * When PPR is enabled, sync:app uses the PPR layout template instead of the default.
 */
function isPPREnabled(projectRoot: string): boolean {
  const configPaths = ['next.config.mjs', 'next.config.js', 'next.config.ts'];
  for (const name of configPaths) {
    const p = join(projectRoot, name);
    if (!existsSync(p)) continue;
    try {
      const content = readFileSync(p, 'utf8');
      if (content.match(/cacheComponents\s*:\s*true/)) {
        return true;
      }
    } catch {
      // ignore read errors
    }
  }
  return false;
}

/**
 * Get the major version of Next.js installed in the project.
 * Returns 0 if not found.
 */
function getNextMajorVersion(projectRoot: string): number {
  try {
    const pkgPath = join(projectRoot, 'node_modules', 'next', 'package.json');
    if (!existsSync(pkgPath)) return 0;
    const pkg = JSON.parse(readFileSync(pkgPath, 'utf8'));
    const match = (pkg.version || '').match(/^(\d+)/);
    return match ? parseInt(match[1], 10) : 0;
  } catch {
    return 0;
  }
}

// Template files that have PPR-specific variants (layout.tsx -> layout.ppr.tsx)
// When PPR is enabled, the .ppr.tsx variant is used instead of the default.
const PPR_TEMPLATE_VARIANTS: Record<string, string> = {
  'layout.tsx': 'layout.ppr.tsx',
};

// Display limits for file listings
const MAX_VERBOSE_FILES = 10;
const MAX_SUMMARY_FILES = 5;

/**
 * Recursively get all files in a directory
 */
function getAllFiles(dir: string, baseDir: string = dir): string[] {
  const files: string[] = [];

  if (!existsSync(dir)) {
    return files;
  }

  const entries = readdirSync(dir, { withFileTypes: true });

  for (const entry of entries) {
    const fullPath = join(dir, entry.name);
    const relativePath = relative(baseDir, fullPath);

    if (entry.isDirectory()) {
      files.push(...getAllFiles(fullPath, baseDir));
    } else if (entry.isFile()) {
      // Skip .DS_Store and README.md
      if (entry.name !== '.DS_Store' && entry.name !== 'README.md') {
        files.push(relativePath);
      }
    }
  }

  return files;
}

/**
 * Copy a file, creating parent directories if needed
 */
function copyFile(source: string, target: string): void {
  const targetDir = dirname(target);
  if (!existsSync(targetDir)) {
    mkdirSync(targetDir, { recursive: true });
  }
  copyFileSync(source, target);
}

/**
 * Backup a directory by copying it
 */
function backupDirectory(source: string, target: string): void {
  if (!existsSync(source)) {
    return;
  }

  const files = getAllFiles(source);
  for (const file of files) {
    const sourcePath = join(source, file);
    const targetPath = join(target, file);
    copyFile(sourcePath, targetPath);
  }
}

/**
 * Get core package version
 */
function getCoreVersion(coreDir: string): string {
  try {
    const pkgPath = join(coreDir, 'package.json');
    const pkg = JSON.parse(readFileSync(pkgPath, 'utf-8'));
    return pkg.version || 'unknown';
  } catch {
    return 'unknown';
  }
}

export async function syncAppCommand(options: SyncAppOptions): Promise<void> {
  const spinner = ora({ text: 'Preparing sync...', isSilent: options.dryRun }).start();

  try {
    const coreDir = getCoreDir();
    const projectRoot = getProjectRoot();
    const coreVersion = getCoreVersion(coreDir);

    // Templates directory in core
    const templatesDir = join(coreDir, 'templates', 'app');

    // Target app directory in project
    const appDir = join(projectRoot, 'app');

    // Verify templates directory exists
    if (!existsSync(templatesDir)) {
      spinner.fail('Templates directory not found in @nextsparkjs/core');
      console.error(chalk.red(`\n  Expected path: ${templatesDir}`));
      process.exit(1);
    }

    // Verify app directory exists (project must be initialized)
    if (!existsSync(appDir)) {
      spinner.fail('No /app directory found');
      console.error(chalk.red('\n  This project does not have an /app folder.'));
      console.error(chalk.yellow('  Run "nextspark init" first to initialize your project.\n'));
      process.exit(1);
    }

    spinner.text = 'Scanning template files...';

    // Get all template files (excluding auto-generated folders and PPR variants)
    // PPR variants (e.g., layout.ppr.tsx) are used as substitutes, not synced as separate files
    const pprVariantFiles = new Set(Object.values(PPR_TEMPLATE_VARIANTS));
    const templateFiles = getAllFiles(templatesDir)
      .filter(f => !EXCLUDED_TEMPLATE_PATTERNS.some(pattern => f.startsWith(pattern)))
      .filter(f => !pprVariantFiles.has(f));

    // Get all existing app files
    const existingAppFiles = getAllFiles(appDir);

    // Determine which files are custom (not in templates)
    const customFiles = existingAppFiles.filter(f => !templateFiles.includes(f));

    // Files that will be updated
    const filesToUpdate = templateFiles;

    spinner.succeed('Scan complete');

    // Show summary
    console.log(chalk.cyan(`\n  Syncing /app with @nextsparkjs/core@${coreVersion}...\n`));

    if (options.dryRun) {
      console.log(chalk.yellow('  [DRY RUN] No changes will be made\n'));
    }

    if (options.verbose) {
      console.log(chalk.gray('  Files to sync:'));
      for (const file of filesToUpdate) {
        const targetPath = join(appDir, file);
        const status = existsSync(targetPath) ? chalk.yellow('update') : chalk.green('create');
        console.log(chalk.gray(`    ${status} ${file}`));
      }
      console.log();
    }

    // Show stats
    console.log(chalk.white(`  Template files: ${filesToUpdate.length}`));
    console.log(chalk.white(`  Custom files preserved: ${customFiles.length}`));

    if (customFiles.length > 0 && options.verbose) {
      console.log(chalk.gray('\n  Custom files (will be preserved):'));
      for (const file of customFiles.slice(0, MAX_VERBOSE_FILES)) {
        console.log(chalk.gray(`    - ${file}`));
      }
      if (customFiles.length > MAX_VERBOSE_FILES) {
        console.log(chalk.gray(`    ... and ${customFiles.length - MAX_VERBOSE_FILES} more`));
      }
    }

    // Confirmation prompt (unless --force or --dry-run)
    if (!options.force && !options.dryRun) {
      console.log(chalk.yellow(`\n  This will overwrite ${filesToUpdate.length} core template files.`));
      console.log(chalk.gray('  Run with --dry-run to preview changes, or --force to skip this prompt.\n'));

      try {
        const { confirm } = await import('@inquirer/prompts');
        const confirmed = await confirm({
          message: 'Proceed with sync?',
          default: true,
        });

        if (!confirmed) {
          console.log(chalk.yellow('\n  Sync cancelled.\n'));
          process.exit(0);
        }
      } catch (promptError) {
        console.error(chalk.red('\n  Failed to load confirmation prompt. Use --force to skip.\n'));
        process.exit(1);
      }
    }

    // Perform backup if requested
    if (options.backup && !options.dryRun) {
      const backupDir = join(projectRoot, `app.backup.v${coreVersion}.${Date.now()}`);
      spinner.start('Creating backup...');
      backupDirectory(appDir, backupDir);
      spinner.succeed(`Backup created: ${relative(projectRoot, backupDir)}`);
    }

    // Perform sync
    if (!options.dryRun) {
      // Detect PPR mode to choose the right template variants
      const pprEnabled = isPPREnabled(projectRoot);
      const nextVersion = getNextMajorVersion(projectRoot);

      if (pprEnabled && nextVersion >= 16) {
        console.log(chalk.cyan('  PPR detected (cacheComponents: true + Next.js 16) — using PPR templates'));
      }

      spinner.start('Syncing files...');

      let updated = 0;
      let created = 0;

      for (const file of filesToUpdate) {
        let sourcePath = join(templatesDir, file);
        const targetPath = join(appDir, file);
        const isNew = !existsSync(targetPath);

        // Use PPR variant if available and PPR is enabled
        const pprVariant = PPR_TEMPLATE_VARIANTS[file];
        if (pprEnabled && nextVersion >= 16 && pprVariant) {
          const pprSourcePath = join(templatesDir, pprVariant);
          if (existsSync(pprSourcePath)) {
            sourcePath = pprSourcePath;
            if (options.verbose) {
              console.log(chalk.cyan(`  ◆ PPR variant: ${file} ← ${pprVariant}`));
            }
          }
        }

        copyFile(sourcePath, targetPath);

        if (isNew) {
          created++;
        } else {
          updated++;
        }

        if (options.verbose) {
          spinner.text = `Syncing: ${file}`;
        }
      }

      spinner.succeed(`Synced ${filesToUpdate.length} files (${updated} updated, ${created} created)`);

      // Sync root template files (proxy.ts, next.config.mjs, etc.)
      const rootTemplatesDir = join(coreDir, 'templates');
      let rootUpdated = 0;
      let rootCreated = 0;

      for (const file of ROOT_TEMPLATE_FILES) {
        const sourcePath = join(rootTemplatesDir, file);
        const targetPath = join(projectRoot, file);

        if (existsSync(sourcePath)) {
          const isNew = !existsSync(targetPath);
          const isProtected = PROTECTED_ROOT_FILES.includes(file);

          // Protected files are only created, never overwritten
          if (isProtected && !isNew) {
            if (options.verbose) {
              console.log(chalk.gray(`  ○ Protected (not overwritten): ${file}`));
            }
            continue;
          }

          copyFile(sourcePath, targetPath);

          if (isNew) {
            rootCreated++;
            if (options.verbose) {
              console.log(chalk.green(`  + Created: ${file}`));
            }
          } else {
            rootUpdated++;
            if (options.verbose) {
              console.log(chalk.yellow(`  ~ Updated: ${file}`));
            }
          }
        }
      }

      if (rootUpdated + rootCreated > 0) {
        console.log(chalk.gray(`  Root files: ${rootUpdated} updated, ${rootCreated} created`));
      }

      // Fix globals.css to use the project's active theme path
      // The template uses ../../../themes/default (monorepo path) but projects use ../../contents/themes/${theme}
      const globalsCssPath = join(appDir, 'globals.css');
      if (existsSync(globalsCssPath)) {
        const envPath = join(projectRoot, '.env');
        let activeTheme = process.env.NEXT_PUBLIC_ACTIVE_THEME;
        if (!activeTheme && existsSync(envPath)) {
          const envContent = readFileSync(envPath, 'utf-8');
          const match = envContent.match(/NEXT_PUBLIC_ACTIVE_THEME=["']?([^"'\s\n]+)["']?/);
          if (match) activeTheme = match[1];
        }
        if (activeTheme && activeTheme !== 'default') {
          const globalsCss = readFileSync(globalsCssPath, 'utf-8');
          const fixed = globalsCss.replace(
            /@import\s+["'][^"']*themes\/[^"']*\/styles\/globals\.css["'];?/,
            `@import "../contents/themes/${activeTheme}/styles/globals.css";`
          );
          if (fixed !== globalsCss) {
            writeFileSync(globalsCssPath, fixed, 'utf-8');
            console.log(chalk.gray(`  Fixed globals.css → themes/${activeTheme}`));
          }
        }
      }
    }

    // Success message
    console.log(chalk.green('\n  \u2705 Sync complete!\n'));

    if (customFiles.length > 0) {
      console.log(chalk.gray(`  Preserved ${customFiles.length} custom file(s):`));
      for (const file of customFiles.slice(0, MAX_SUMMARY_FILES)) {
        console.log(chalk.gray(`    - app/${file}`));
      }
      if (customFiles.length > MAX_SUMMARY_FILES) {
        console.log(chalk.gray(`    ... and ${customFiles.length - MAX_SUMMARY_FILES} more\n`));
      } else {
        console.log();
      }
    }

  } catch (error) {
    spinner.fail('Sync failed');
    if (error instanceof Error) {
      console.error(chalk.red(`\n  Error: ${error.message}\n`));
      if (options.verbose && error.stack) {
        console.error(chalk.gray(`  Stack trace:\n${error.stack}\n`));
      }
    }
    process.exit(1);
  }
}
